good-example.code-block:
Feature: User registration API
As a client I want to register a new user via REST API So that I can create an account
@acceptance Scenario: Successful user registration Given the system is ready When I send a POST request to "/api/users" with: """ {"email": "user@example.com", "name": "John Doe"} """ Then the response status is 201 And the response body contains "id" And the response body "email" equals "user@example.com"
@acceptance Scenario: Get user by id Given a user exists with email "user@example.com" When I send a GET request to "/api/users/1" Then the response status is 200 And the response body "email" equals "user@example.com"

package com.example.myapp;

import com.github.tomakehurst.wiremock.junit5.WireMockExtension;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.extension.RegisterExtension;
import org.testcontainers.containers.KafkaContainer;
import org.testcontainers.containers.PostgreSQLContainer;
import org.testcontainers.junit.jupiter.Container;
import org.testcontainers.junit.jupiter.Testcontainers;
import org.testcontainers.utility.DockerImageName;

import static com.github.tomakehurst.wiremock.core.WireMockConfiguration.wireMockConfig;

@Testcontainers
abstract class BaseAcceptanceTest {

    protected static int port;

    @Container
    static PostgreSQLContainer<?> postgres = new PostgreSQLContainer<>(DockerImageName.parse("postgres:16-alpine"))
        .withDatabaseName("testdb")
        .withUsername("test")
        .withPassword("test");

    @Container
    static KafkaContainer kafka = new KafkaContainer(DockerImageName.parse("apache/kafka:3.8"));

    @RegisterExtension
    static WireMockExtension wireMock = WireMockExtension.newInstance()
        .options(wireMockConfig().dynamicPort().usingFilesUnderClasspath("wiremock"))
        .build();

    @BeforeAll
    static void setUpInfrastructure() {
        System.setProperty("datasource.url", postgres.getJdbcUrl());
        System.setProperty("datasource.username", postgres.getUsername());
        System.setProperty("datasource.password", postgres.getPassword());
        System.setProperty("kafka.bootstrap.servers", kafka.getBootstrapServers());
        System.setProperty("external.service.base-url", wireMock.baseUrl());
        // Start app programmatically (Javalin/Spark/Jetty/etc.) and assign port = app.port();
        port = App.start();
    }
}

